[CmdletBinding()]
param([Parameter(Mandatory=$true)][string]$BackupFile,[Parameter(Mandatory=$true)][string]$TargetDatabase,[string]$DatabaseUrl,[string]$EnvFile,[string]$PgBinDir)
$ErrorActionPreference='Stop';if($EnvFile -and (Test-Path $EnvFile)){Get-Content $EnvFile|%{if($_ -match '^([^#=]+)=(.*)$'){[Environment]::SetEnvironmentVariable($Matches[1],$Matches[2])}}};if(!$DatabaseUrl){$DatabaseUrl=$env:DATABASE_URL};if(!$DatabaseUrl -and $env:DB_HOST -and $env:DB_NAME -and $env:DB_USER){$port=if($env:DB_PORT){$env:DB_PORT}else{5432};$DatabaseUrl="postgresql://$([Uri]::EscapeDataString($env:DB_USER)):$([Uri]::EscapeDataString($env:DB_PASSWORD))@$($env:DB_HOST):$port/$($env:DB_NAME)"};if(!$DatabaseUrl){throw 'DatabaseUrl is required'};if(!$PgBinDir){$PgBinDir=$env:PG_BIN_DIR};if(!$PgBinDir -or !(Test-Path $PgBinDir)){throw 'PG_BIN_DIR missing'};$restore=Join-Path $PgBinDir 'pg_restore.exe';$psql=Join-Path $PgBinDir 'psql.exe';if(!(Test-Path $restore) -or !(Test-Path $psql)){throw 'tools missing'}
$u=[Uri]$DatabaseUrl;$sep=$u.UserInfo.IndexOf(':');if($sep -lt 0){throw 'DatabaseUrl userinfo must include password'};$user=[Uri]::UnescapeDataString($u.UserInfo.Substring(0,$sep));$password=[Uri]::UnescapeDataString($u.UserInfo.Substring($sep+1));$prod=$u.AbsolutePath.Trim('/');if($env:PRODUCTION_DB_NAME){$prod=$env:PRODUCTION_DB_NAME};if($TargetDatabase.Equals($prod,[StringComparison]::OrdinalIgnoreCase)){throw 'production target refused'};if(!(Test-Path $BackupFile)){throw 'backup missing'};$expected=(Get-Content "$BackupFile.sha256" -Raw).Trim().Split()[0];if($expected -ne (Get-FileHash $BackupFile -Algorithm SHA256).Hash){throw 'checksum mismatch'};&$restore --list $BackupFile|Out-Null;if($LASTEXITCODE){throw 'invalid archive'}
$old=$env:PGPASSWORD;$env:PGHOST=$u.Host;$env:PGPORT=($(if($u.Port -gt 0){$u.Port}else{5432}));$env:PGUSER=$user;$env:PGPASSWORD=$password;$env:PGDATABASE=$TargetDatabase;try{$rows=&$psql --tuples-only --no-align --command "SELECT 1 FROM pg_catalog.pg_tables WHERE schemaname NOT IN ('pg_catalog','information_schema') LIMIT 1";if($LASTEXITCODE -or $rows -match '1'){throw 'target unavailable or not empty'};&$restore --exit-on-error --single-transaction --no-owner --no-privileges --dbname $TargetDatabase $BackupFile; if($LASTEXITCODE){throw 'restore failed'}}finally{$env:PGPASSWORD=$old}
